class ErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { hasError: false, errorMsg: '' }; }
  static getDerivedStateFromError(error) { return { hasError: true }; }
  componentDidCatch(error) { this.setState({ errorMsg: error && error.message ? error.message : String(error) }); }
  render() {
    if (this.state.hasError) return (<div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 p-6 print:hidden"><AlertTriangle size={60} className="text-red-500 mb-4" /><h2 className="text-2xl font-black text-black uppercase mb-2">Error de Sistema Capturado</h2><p className="text-gray-500 text-sm mb-6">{this.state.errorMsg}</p><button onClick={() => window.location.reload()} className="bg-black text-white font-black px-8 py-4 rounded-xl uppercase tracking-widest text-xs shadow-lg">Recargar Interfaz</button></div>);
    return this.props.children; 
  }
}

const compressImage = (file, cb) => { const r = new FileReader(); r.readAsDataURL(file); r.onload = e => { const img = new Image(); img.src = e.target.result; img.onload = () => { const cvs = document.createElement('canvas'); const ctx = cvs.getContext('2d'); const MAX = 1920; let w = img.width; let h = img.height; if (w > MAX) { h *= MAX / w; w = MAX; } cvs.width = w; cvs.height = h; ctx.drawImage(img, 0, 0, w, h); cb(cvs.toDataURL('image/jpeg', 0.6)); }; }; };
