const formatNum = (n) => new Intl.NumberFormat('es-VE', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(n || 0);
const parseNum = (v) => { if (!v) return 0; if (typeof v === 'number') return v; let s = String(v||'').trim(); if (s.includes('.') && s.includes(',')) s = s.replace(/\./g, '').replace(',', '.'); else if (s.includes(',')) s = s.replace(',', '.'); const p = parseFloat(s); return isNaN(p) ? 0 : p; };
